import pytest

def test_approve_reject_decision_table_all_role_states(
    pending_leave_request,   # <fixture>: yields {id} assigned to manager_A
    get_api_client,          # <fixture>: factory fn(role) -> authenticated HTTP client
):
    req_id = pending_leave_request["id"]
    endpoint = f"/api/leave-requests/{req_id}/approve"

    cases = [
        ("manager_assignee", 200, "approved"),
        ("manager_other",    403, "pending"),
        ("hr_admin",         403, "pending"),
    ]

    for role, expected_status, expected_state in cases:
        client = get_api_client(role)
        resp = client.post(endpoint)
        assert resp.status_code == expected_status, (
            f"Role={role}: expected HTTP {expected_status}, got {resp.status_code}"
        )

        if expected_status != 200:
            state_resp = get_api_client("manager_assignee").get(
                f"/api/leave-requests/{req_id}"
            )
            assert state_resp.json()["state"] == expected_state, (
                f"Role={role}: state should remain {expected_state}"
            )
        else:
            assert resp.json()["state"] == "approved"
